import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }

    static boolean isBST(Node node, long min, long max) {
        if (node == null) return true;
        if (node.val <= min || node.val >= max) return false;
        return isBST(node.left, min, node.val) && isBST(node.right, node.val, max);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String line = br.readLine();
        if (line == null || line.trim().isEmpty()) {
            System.out.print("");
            return;
        }
        int T = Integer.parseInt(line.trim());
        for (int t = 0; t < T; t++) {
            int N;
            // read N, skipping empty lines
            while (true) {
                line = br.readLine();
                if (line != null && !line.trim().isEmpty()) {
                    N = Integer.parseInt(line.trim());
                    break;
                }
            }
            if (N == 1) {
                out.append("YES");
                if (t != T - 1) out.append('\n');
                continue;
            }
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = map.computeIfAbsent(p, k -> new Node(k));
                Node child = map.computeIfAbsent(c, k -> new Node(k));
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (int val : map.keySet()) {
                if (!childSet.contains(val)) {
                    root = map.get(val);
                    break;
                }
            }
            out.append(isBST(root, Long.MIN_VALUE, Long.MAX_VALUE) ? "YES" : "NO");
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

